const pages = $input.all().map(i => i.json);

// Only use scripts that have at least one metric filled
const scored = pages.filter(p => {
  const views = p.properties?.Views?.number;
  const likes = p.properties?.Likes?.number;
  const comments = p.properties?.Comments?.number;
  return views != null || likes != null || comments != null;
});

if (scored.length === 0) {
  return [{ json: { error: 'No scripts with metrics found', winners: [] } }];
}

const getVal = (p, key) => p.properties?.[key]?.number || 0;
const getTitle = (p) => {
  const t = p.properties?.title?.title || p.properties?.Name?.title || [];
  return t.map(r => r.plain_text).join('') || p.id;
};
const getFunnel = (p) => p.properties?.['Funnel Stage']?.select?.name || 'Unknown';

const topViews = [...scored].sort((a,b) => getVal(b,'Views') - getVal(a,'Views'))[0];
const topLikes = [...scored].sort((a,b) => getVal(b,'Likes') - getVal(a,'Likes'))[0];
const topComments = [...scored].sort((a,b) => getVal(b,'Comments') - getVal(a,'Comments'))[0];

const winners = [];
const seen = new Set();

for (const [winner, metric] of [[topViews,'Views'],[topLikes,'Likes'],[topComments,'Comments']]) {
  if (winner && !seen.has(winner.id)) {
    seen.add(winner.id);
    winners.push({
      id: winner.id,
      title: getTitle(winner),
      funnel_stage: getFunnel(winner),
      winning_metric: metric,
      views: getVal(winner,'Views'),
      likes: getVal(winner,'Likes'),
      comments: getVal(winner,'Comments'),
      hook: winner.properties?.Hook?.rich_text?.[0]?.plain_text || '',
      body_structure: winner.properties?.['Body Structure']?.rich_text?.[0]?.plain_text || '',
      cta: winner.properties?.CTA?.rich_text?.[0]?.plain_text || '',
      format: winner.properties?.Format?.select?.name || '',
      tone: winner.properties?.Tone?.select?.name || '',
      topics: (winner.properties?.Topics?.multi_select || []).map(t => t.name)
    });
  }
}

return winners.length ? winners.map(w => ({ json: w })) : [{ json: { error: 'All winners same script', winners: [] } }];

