  {
    variation: 'V1',
    element_copied: 'Hook',
    parent_id: winner.id,
    parent_title: winner.title,
    winning_metric: winner.winning_metric,
    prompt: SYSTEM + '\n\nCreate a new script copying ONLY the hook style from this winner. Change everything else.\n\n' + base
  },
  {
    variation: 'V2',
    element_copied: 'Format',
    parent_id: winner.id,
    parent_title: winner.title,
    winning_metric: winner.winning_metric,
    prompt: SYSTEM + '\n\nCreate a new script copying ONLY the format/structure from this winner. Change hook, CTA, and content.\n\n' + base
  },
  {
    variation: 'V3',
    element_copied: 'CTA',
    parent_id: winner.id,
    parent_title: winner.title,
    winning_metric: winner.winning_metric,
    prompt: SYSTEM + '\n\nCreate a new script copying ONLY the CTA style from this winner. Change hook and body.\n\n' + base
  },
  {
    variation: 'V4',
    element_copied: 'Topics',
    parent_id: winner.id,
    parent_title: winner.title,
    winning_metric: winner.winning_metric,
    prompt: SYSTEM + '\n\nCreate a new script on the same topics as this winner but with a completely different angle, hook, and structure.\n\nTopics: ' + winner.topics.join(', ') + '\n\n' + base
  },
  {
    variation: 'V5',
    element_copied: 'Structure',
    parent_id: winner.id,
    parent_title: winner.title,
    winning_metric: winner.winning_metric,
    prompt: SYSTEM + '\n\nCreate a new script copying ONLY the body structure pattern from this winner. New hook, new CTA, new content.\n\n' + base
  }
];

return variations.map(v => ({ json: v }));

